// Input sanitization
object InputSanitizer {

  // Reject any argument containing shell metacharacters
  private val dangerousPattern = """[;&|`$(){}\[\]!#~<>*?\\\n\r"']""".r

  def sanitizeArgument(arg: String): Either[String, String] = {
    if (arg.isEmpty) {
      Left("Empty argument not allowed")
    } else if (arg.length > 256) {
      Left(s"Argument too long: max 256 characters, got ${arg.length}")
    } else if (dangerousPattern.findFirstIn(arg).isDefined) {
      Left(s"Argument contains forbidden characters: $arg")
    } else {
      Right(arg.trim)
    }
  }

  def sanitizeAllArguments(args: List[String]): Either[String, List[String]] = {
    val results = args.map(sanitizeArgument)
    val errors = results.collect { case Left(err) => err }
    if (errors.nonEmpty) {
      Left(s"Invalid arguments: ${errors.mkString(", ")}")
    } else {
      Right(results.collect { case Right(a) => a })
    }
  }
}

// Safe command execution service
class CommandExecutionService {

  private val maxArgs = 20
  private val timeoutSeconds = 30

  def execute(request: CommandRequest): Either[String, CommandResult] = {
    for {
      binaryPath <- resolveCommand(request.command)
      sanitizedArgs <- validateAndSanitizeArgs(request.args)
      result <- runProcess(binaryPath, sanitizedArgs)
    } yield result
  }

  private def resolveCommand(commandAlias: String): Either[String, String] = {
    AllowedCommands.whitelist.get(commandAlias) match {
      case Some(path) => Right(path)
      case None =>
        Left(s"Command '$commandAlias' is not in the allowed commands list. " +
          s"Available commands: ${AllowedCommands.whitelist.keys.mkString(", ")}")
    }
  }

  private def validateAndSanitizeArgs(args: List[String]): Either[String, List[String]] = {
    if (args.length > maxArgs) {
      Left(s"Too many arguments: max $maxArgs, got ${args.length}")
    } else {
      InputSanitizer.sanitizeAllArguments(args)
    }
  }

  // SAFE: Uses Seq[String] form which does NOT invoke a shell.
  // Each element is passed as a separate argv entry to the process.
  // This prevents shell injection entirely.
  private def runProcess(binaryPath: String, args: List[String]): Either[String, CommandResult] = {
    Try {
      val command: Seq[String] = binaryPath +: args

      val stdoutBuilder = new StringBuilder
      val stderrBuilder = new StringBuilder

      val processLogger = ProcessLogger(
        (out: String) => stdoutBuilder.append(out).append("\n"),
        (err: String) => stderrBuilder.append(err).append("\n")
      )

      // SAFE: Process(Seq[String]) does NOT use a shell interpreter.
      // Arguments are passed directly as argv, preventing injection.
      val exitCode = Process(command).!(processLogger)

      CommandResult(
        exitCode = exitCode,
        stdout = stdoutBuilder.toString().trim,
        stderr = stderrBuilder.toString().trim
      )
    } match {
      case Success(result) => Right(result)
      case Failure(ex) => Left(s"Command execution failed: ${ex.getMessage}")
    }
  }
}

